+                    // parse_chunk_size_line() behavior.
+                    let size_part = line_str.split(';').next().unwrap_or("");
                     if size_part.is_empty() {
                         return Err(HttpError::BadChunkedEncoding);
                     }
+                    if size_part
+                        .as_bytes()
+                        .first()
+                        .is_some_and(u8::is_ascii_whitespace)
